using System;
using System.Text.Json;

namespace AvatarBuilder.Modules.Vision.MediaPipe.Reconstruction.Stereo;

public static class MediaPipeStereoProbabilityFaceViewerPage
{
	private static readonly JsonSerializerOptions JsonOptions = new JsonSerializerOptions(JsonSerializerDefaults.Web);

	public static string Build(MediaPipeStereoProbabilityFaceModel model)
	{
		ArgumentNullException.ThrowIfNull(model, "model");
		string text = JsonSerializer.Serialize(model, JsonOptions).Replace("</", "<\\/", StringComparison.Ordinal);
		return "<!doctype html>\n<html lang=\"en\">\n<head>\n  <meta charset=\"utf-8\">\n  <meta name=\"viewport\" content=\"width=device-width,initial-scale=1\">\n  <title>Probability Face</title>\n  <style>\n    :root{color-scheme:dark;font-family:\"Segoe UI\",Arial,sans-serif;background:#061019;color:#e7f4ff}\n    *{box-sizing:border-box}body{margin:0;min-height:100vh;background:#061019}\n    header{height:54px;display:flex;align-items:center;gap:8px;padding:8px 12px;border-bottom:1px solid #254052;background:#0a1721}\n    button{color:#e7f4ff;background:#10283a;border:1px solid #397397;padding:8px 12px;cursor:pointer}button:hover{border-color:#63c9ff}button[aria-pressed=\"true\"]{background:#15567a;border-color:#63c9ff}.spacer{flex:1}\n    .layout{height:calc(100vh - 54px);display:grid;grid-template-columns:minmax(0,1fr) 360px}.stage{position:relative;min-width:0;overflow:hidden}\n    canvas{width:100%;height:100%;display:block;background:#040b11;touch-action:none}.hint{position:absolute;left:14px;top:12px;padding:8px 10px;background:#07121dcc;border:1px solid #20394b;color:#b9d7ef;font-size:12px;pointer-events:none}\n    aside{overflow:auto;padding:16px;border-left:1px solid #254052;background:#08141d}h1{margin:0 0 4px;font-size:20px;letter-spacing:0}h2{margin:20px 0 8px;font-size:13px;color:#80e0a4;letter-spacing:0}\n    p{margin:5px 0;line-height:1.4}.muted{color:#9ebdd2;font-size:12px}.status{color:#ffd27a}.metric{display:grid;grid-template-columns:1fr auto;gap:10px;padding:7px 0;border-bottom:1px solid #193044;font-size:12px}.metric strong{color:#dff5ff;font-variant-numeric:tabular-nums}\n    .bar{height:7px;margin-top:10px;background:#13283a;border:1px solid #27485f}.bar span{display:block;height:100%;background:#66e8b0}.note{margin-top:16px;padding:10px;border:1px solid #2c627f;color:#bfe9ff;background:#081b27;font-size:12px;line-height:1.4}\n    @media(max-width:800px){.layout{grid-template-columns:1fr;grid-template-rows:minmax(420px,65vh) auto;height:auto}aside{border-left:0;border-top:1px solid #254052}}\n  </style>\n</head>\n<body>\n  <header><button id=\"smooth\" aria-pressed=\"true\">Smooth Face</button><button id=\"measured\" aria-pressed=\"false\">Measured Surface</button><button id=\"wire\" aria-pressed=\"false\">Wireframe</button><button id=\"points\" aria-pressed=\"false\">Measured Samples</button><button id=\"front\">Front</button><button id=\"side\">Side</button><button id=\"reset\">Reset 3D View</button><span class=\"spacer\"></span><button id=\"refresh\">Refresh Page</button></header>\n  <main class=\"layout\">\n    <section class=\"stage\"><canvas id=\"view\"></canvas><div class=\"hint\">Drag to rotate; wheel to zoom. Smooth Face is derived from the probability peaks without changing the measurements.</div></section>\n    <aside><h1>Probability Face</h1><p><strong id=\"subject\"></strong></p><p class=\"muted\" id=\"updated\"></p><p class=\"status\" id=\"status\"></p><h2>Extracted Surface</h2><div id=\"metrics\"></div><div class=\"bar\"><span id=\"confidenceBar\"></span></div>\n      <div class=\"note\">Measured Surface selects the strongest repeated depth in each small face region. Smooth Face fills only well-surrounded interior gaps and smooths low-confidence depth while preserving strong edges. Measured Samples always remain available underneath, and none of the source evidence is overwritten.</div>\n    </aside>\n  </main>\n  <script>\n    const model=" + text + ",canvas=document.getElementById('view'),gl=canvas.getContext('webgl',{alpha:false,antialias:true,preserveDrawingBuffer:false}),key='avatarBuilder.probabilityFaceView.v2';\n    let saved={};try{saved=JSON.parse(localStorage.getItem(key)||'{}')}catch{}const view={yaw:Number.isFinite(saved.yaw)?saved.yaw:-.28,pitch:Number.isFinite(saved.pitch)?saved.pitch:.05,zoom:Number.isFinite(saved.zoom)?saved.zoom:.82,mode:saved.mode==='measured'?'measured':'smooth',wire:saved.wire===true,points:saved.points===true};let dragging=false,lastX=0,lastY=0;\n    const finite=v=>Number.isFinite(Number(v))?Number(v):0,fmt=(v,d=2)=>finite(v).toFixed(d),metric=(l,v)=>`<div class=\"metric\"><span>${l}</span><strong>${v}</strong></div>`,save=()=>localStorage.setItem(key,JSON.stringify(view)),pressed=(id,v)=>document.getElementById(id).setAttribute('aria-pressed',v?'true':'false');\n    document.getElementById('subject').textContent=model.subjectDisplayName||model.subjectId||'No profile';document.getElementById('updated').textContent=model.evidenceUpdatedAtUtc?`Evidence through ${new Date(model.evidenceUpdatedAtUtc).toLocaleString()}`:'Waiting for evidence';document.getElementById('status').textContent=model.status||'';\n    const measuredVertices=model.vertices||[],measuredTriangles=model.triangles||[],smoothVertices=(model.smoothedVertices||[]).length?model.smoothedVertices:measuredVertices,smoothTriangles=(model.smoothedTriangles||[]).length?model.smoothedTriangles:measuredTriangles,interpolated=smoothVertices.filter(v=>v.isInterpolated).length;\n    document.getElementById('metrics').innerHTML=metric('Smooth vertices',Number(smoothVertices.length).toLocaleString())+metric('Smooth triangles',Number(smoothTriangles.length).toLocaleString())+metric('Filled interior samples',Number(interpolated).toLocaleString())+metric('Measured probability peaks',Number(measuredVertices.length).toLocaleString())+metric('Measured triangles',Number(measuredTriangles.length).toLocaleString())+metric('Repeated source bins',Number(model.repeatedSourceBinCount||0).toLocaleString())+metric('Source observations',Number(model.sourceObservationCount||0).toLocaleString())+metric('Mean surface confidence',`${fmt(model.meanConfidencePercent,1)}%`)+metric('Surface resolution',`${fmt(model.surfaceCellSizeInches,2)} in`)+metric('Face width',`${fmt(model.faceWidthInches)} in`)+metric('Face height',`${fmt(model.faceHeightInches)} in`)+metric('Depth span',`${fmt(model.faceDepthInches)} in`);document.getElementById('confidenceBar').style.width=`${Math.max(0,Math.min(100,finite(model.meanConfidencePercent)))}%`;\n    if(!gl){document.querySelector('.hint').textContent='WebGL is unavailable in this browser.';throw new Error('WebGL unavailable')}\n    const vertex=`attribute vec3 p;attribute vec3 n;attribute float confidence;uniform float yaw;uniform float pitch;uniform float zoom;uniform vec3 center;uniform float span;uniform vec2 viewportScale;varying vec3 normal;varying float trust;void main(){vec3 q=p-center;float cy=cos(yaw),sy=sin(yaw),cp=cos(pitch),sp=sin(pitch);vec3 y=vec3(cy*q.x+sy*q.z,q.y,-sy*q.x+cy*q.z);vec3 r=vec3(y.x,cp*y.y-sp*y.z,sp*y.y+cp*y.z);vec3 yn=vec3(cy*n.x+sy*n.z,n.y,-sy*n.x+cy*n.z);normal=normalize(vec3(yn.x,cp*yn.y-sp*yn.z,sp*yn.y+cp*yn.z));trust=confidence;gl_Position=vec4((r.xy/max(span,.001))*2.0*zoom*viewportScale,-r.z/max(span,.001)*.25,1.0);gl_PointSize=2.4;}`;\n    const surfaceFragment=`precision mediump float;varying vec3 normal;varying float trust;void main(){vec3 N=normalize(normal);float diffuse=.22+.72*abs(dot(N,normalize(vec3(-.35,.65,.72))));float rim=pow(1.0-abs(N.z),2.2)*.24;vec3 low=vec3(.045,.17,.21),high=vec3(.31,.78,.82),base=mix(low,high,.38+.62*trust);gl_FragColor=vec4(base*diffuse+vec3(.12,.42,.46)*rim,1.0);}`;\n    const lineFragment=`precision mediump float;varying float trust;void main(){gl_FragColor=vec4(mix(vec3(.12,.42,.52),vec3(.45,.93,1.0),trust),.72);}`;\n    const pointFragment=`precision mediump float;varying float trust;void main(){vec2 d=gl_PointCoord-vec2(.5);if(dot(d,d)>.25)discard;gl_FragColor=vec4(mix(vec3(.35,.65,.72),vec3(.75,1.0,.88),trust),.95);}`;\n    function shader(type,source){const s=gl.createShader(type);gl.shaderSource(s,source);gl.compileShader(s);if(!gl.getShaderParameter(s,gl.COMPILE_STATUS))throw new Error(gl.getShaderInfoLog(s));return s}function program(fragment){const p=gl.createProgram();gl.attachShader(p,shader(gl.VERTEX_SHADER,vertex));gl.attachShader(p,shader(gl.FRAGMENT_SHADER,fragment));gl.linkProgram(p);if(!gl.getProgramParameter(p,gl.LINK_STATUS))throw new Error(gl.getProgramInfoLog(p));return p}const programs={surface:program(surfaceFragment),line:program(lineFragment),point:program(pointFragment)};\n    function buffer(target,data){const b=gl.createBuffer();gl.bindBuffer(target,b);gl.bufferData(target,data,gl.STATIC_DRAW);return b}\n    function createGeometry(vertices,triangles){const count=vertices.length,positions=new Float32Array(count*3),confidence=new Float32Array(count),normals=new Float32Array(count*3);let min=[Infinity,Infinity,Infinity],max=[-Infinity,-Infinity,-Infinity];for(let i=0;i<count;i++){const v=vertices[i];positions[i*3]=finite(v.xInches);positions[i*3+1]=finite(v.yInches);positions[i*3+2]=finite(v.zInches);confidence[i]=Math.max(0,Math.min(1,finite(v.confidencePercent)/100));for(let a=0;a<3;a++){min[a]=Math.min(min[a],positions[i*3+a]);max[a]=Math.max(max[a],positions[i*3+a])}}const indices=new Uint16Array(triangles.length*3);for(let i=0;i<triangles.length;i++){const t=triangles[i],a=Number(t.a),b=Number(t.b),c=Number(t.c);indices.set([a,b,c],i*3);const ax=positions[b*3]-positions[a*3],ay=positions[b*3+1]-positions[a*3+1],az=positions[b*3+2]-positions[a*3+2],bx=positions[c*3]-positions[a*3],by=positions[c*3+1]-positions[a*3+1],bz=positions[c*3+2]-positions[a*3+2],nx=ay*bz-az*by,ny=az*bx-ax*bz,nz=ax*by-ay*bx;for(const p of[a,b,c]){normals[p*3]+=nx;normals[p*3+1]+=ny;normals[p*3+2]+=nz}}for(let i=0;i<count;i++){const x=normals[i*3],y=normals[i*3+1],z=normals[i*3+2],length=Math.hypot(x,y,z)||1;normals[i*3]=x/length;normals[i*3+1]=y/length;normals[i*3+2]=z/length}const edgeSet=new Set(),edgeValues=[];for(const t of triangles){for(const edge of[[Number(t.a),Number(t.b)],[Number(t.b),Number(t.c)],[Number(t.c),Number(t.a)]]){const a=Math.min(edge[0],edge[1]),b=Math.max(edge[0],edge[1]),k=`${a}:${b}`;if(!edgeSet.has(k)){edgeSet.add(k);edgeValues.push(a,b)}}}if(!count){min=[-1,-1,-1];max=[1,1,1]}return{count,positions,confidence,normals,indices,edges:new Uint16Array(edgeValues),center:min.map((v,i)=>(v+max[i])/2),span:Math.max(.5,max[0]-min[0],max[1]-min[1],max[2]-min[2]),positionBuffer:buffer(gl.ARRAY_BUFFER,positions),normalBuffer:buffer(gl.ARRAY_BUFFER,normals),confidenceBuffer:buffer(gl.ARRAY_BUFFER,confidence),triangleBuffer:buffer(gl.ELEMENT_ARRAY_BUFFER,indices),edgeBuffer:buffer(gl.ELEMENT_ARRAY_BUFFER,new Uint16Array(edgeValues))}}\n    const measuredGeometry=createGeometry(measuredVertices,measuredTriangles),smoothGeometry=createGeometry(smoothVertices,smoothTriangles),activeGeometry=()=>view.mode==='smooth'&&smoothGeometry.count?smoothGeometry:measuredGeometry;\n    function bind(program,geometry,frame){gl.useProgram(program);for(const [name,b,size]of[['p',geometry.positionBuffer,3],['n',geometry.normalBuffer,3],['confidence',geometry.confidenceBuffer,1]]){const location=gl.getAttribLocation(program,name);if(location<0)continue;gl.bindBuffer(gl.ARRAY_BUFFER,b);gl.enableVertexAttribArray(location);gl.vertexAttribPointer(location,size,gl.FLOAT,false,0,0)}gl.uniform1f(gl.getUniformLocation(program,'yaw'),view.yaw);gl.uniform1f(gl.getUniformLocation(program,'pitch'),view.pitch);gl.uniform1f(gl.getUniformLocation(program,'zoom'),view.zoom);gl.uniform3fv(gl.getUniformLocation(program,'center'),new Float32Array(frame.center));gl.uniform1f(gl.getUniformLocation(program,'span'),frame.span);const aspect=canvas.clientWidth/Math.max(1,canvas.clientHeight);gl.uniform2f(gl.getUniformLocation(program,'viewportScale'),aspect>=1?1/aspect:1,aspect>=1?1:aspect)}\n    gl.clearColor(.016,.043,.067,1);gl.enable(gl.DEPTH_TEST);function draw(){const geometry=activeGeometry();gl.clear(gl.COLOR_BUFFER_BIT|gl.DEPTH_BUFFER_BIT);if(geometry.indices.length){bind(programs.surface,geometry,geometry);gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER,geometry.triangleBuffer);gl.drawElements(gl.TRIANGLES,geometry.indices.length,gl.UNSIGNED_SHORT,0)}if(view.wire&&geometry.edges.length){bind(programs.line,geometry,geometry);gl.bindBuffer(gl.ELEMENT_ARRAY_BUFFER,geometry.edgeBuffer);gl.drawElements(gl.LINES,geometry.edges.length,gl.UNSIGNED_SHORT,0)}if(view.points&&measuredGeometry.count){bind(programs.point,measuredGeometry,geometry);gl.drawArrays(gl.POINTS,0,measuredGeometry.count)}}\n    function resize(){const dpr=Math.min(2,window.devicePixelRatio||1),r=canvas.getBoundingClientRect(),w=Math.max(1,Math.round(r.width*dpr)),h=Math.max(1,Math.round(r.height*dpr));if(canvas.width!==w||canvas.height!==h){canvas.width=w;canvas.height=h;gl.viewport(0,0,w,h)}draw()}new ResizeObserver(resize).observe(canvas);\n    function selectMode(mode){view.mode=mode;pressed('smooth',mode==='smooth');pressed('measured',mode==='measured');save();draw()}function toggle(id,name){view[name]=!view[name];pressed(id,view[name]);save();draw()}document.getElementById('smooth').onclick=()=>selectMode('smooth');document.getElementById('measured').onclick=()=>selectMode('measured');document.getElementById('wire').onclick=()=>toggle('wire','wire');document.getElementById('points').onclick=()=>toggle('points','points');document.getElementById('front').onclick=()=>{view.yaw=0;view.pitch=0;save();draw()};document.getElementById('side').onclick=()=>{view.yaw=-Math.PI/2;view.pitch=0;save();draw()};document.getElementById('reset').onclick=()=>{view.yaw=-.28;view.pitch=.05;view.zoom=.82;save();draw()};document.getElementById('refresh').onclick=()=>location.reload();pressed('smooth',view.mode==='smooth');pressed('measured',view.mode==='measured');pressed('wire',view.wire);pressed('points',view.points);\n    canvas.addEventListener('pointerdown',e=>{dragging=true;lastX=e.clientX;lastY=e.clientY;canvas.setPointerCapture(e.pointerId)});canvas.addEventListener('pointermove',e=>{if(!dragging)return;view.yaw+=(e.clientX-lastX)*.008;view.pitch=Math.max(-1.55,Math.min(1.55,view.pitch+(e.clientY-lastY)*.008));lastX=e.clientX;lastY=e.clientY;draw()});canvas.addEventListener('pointerup',()=>{dragging=false;save()});canvas.addEventListener('wheel',e=>{e.preventDefault();view.zoom=Math.max(.08,Math.min(6,view.zoom*Math.exp(-e.deltaY*.001)));save();draw()},{passive:false});\n  </script>\n</body>\n</html>";
	}
}
